module ramp_a_tone ( input rst, input clk, output reg [15:0] tone );
	reg down;
	always @(posedge rst or posedge clk) begin
		if( rst ) begin
			down   <= 0;
			tone <= 0;
		end
		else begin
			if( tone == 16'hFFFE ) begin
				down <= 1'b0;
			end
			else if( tone == 16'h1 ) begin
				down <= 1'b1;
			end
			tone <= down ? (tone+1'b1) : (tone-1'b1);
		end
	end
endmodule
